function solve(nums) {
    // This problem asks for the maximum number of fixed points achievable
    // after deleting any number of elements.
    // A fixed point at index j means the value at that index is j.
    //
    // Let the original array be nums.
    // If we decide to keep a subset of indices from the original array, say original indices i_1, i_2, ..., i_k (where i_1 < i_2 < ... < i_k).
    // In the new array, the element originally at nums[i_j] will be at the new index j-1 (using 0-based indexing).
    // For this element to be a fixed point, we need nums[i_j] == (j-1).
    //
    // Let's rephrase: we are selecting a subsequence of nums: nums[i_0], nums[i_1], ..., nums[i_{k-1}].
    // The new index for nums[i_j] is j.
    // We want to maximize k such that for all j in [0, k-1], nums[i_j] == j.
    //
    // This is equivalent to finding the Longest Increasing Subsequence (LIS) with a specific constraint,
    // or more simply, a greedy approach works here.
    //
    // We iterate through the original array and try to greedily satisfy the condition.
    // We maintain a counter `current_target_index`, which represents the required value (the new index) for the next element we want to keep as a fixed point.
    // Initially, we want the first kept element to be at index 0, so the target value is 0.

    let fixedPoints = 0;
    let currentTargetIndex = 0; // The required value (new index) for the next kept element to be a fixed point.

    for (let i = 0; i < nums.length; i++) {
        // We check if the value nums[i] can serve as the next fixed point in the constructed subsequence.
        // If we keep nums[i], it will occupy the position `fixedPoints` in the resulting array.
        // For it to be a fixed point, we need nums[i] == fixedPoints.

        if (nums[i] === currentTargetIndex) {
            // We found an element nums[i] that matches the required index/value.
            // We decide to keep it. This contributes one fixed point.
            fixedPoints++;
            // The next fixed point we look for must be at the next index, which is fixedPoints.
            currentTargetIndex++;
        }
        // If nums[i] != currentTargetIndex, we skip (delete) this element, hoping a later element
        // will match the currentTargetIndex.
    }

    return fixedPoints;
}

